#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <cctype>

bool isPalindrome(const std::string& s);

int main() {
    std::vector<std::pair<std::string, bool>> test_cases = {
        {"Race car", true},
        {"Madam", true},
        {"A man, a plan, a canal: Panama", true},
        {"hello", false},
        {"No lemon, no melon", true},
        {"12321", true},
        {"Was it a car or a cat I saw?", true},
        {"", true},
        {"  ", true},
        {"level", true},
        {"world", false}
    };

    for (const auto& tc : test_cases) {
        bool result = isPalindrome(tc.first);
        std::cout << "Input: \"" << tc.first << "\", Expected: " << (tc.second ? "true" : "false")
                  << ", Got: " << (result ? "true" : "false") << std::endl;
    }

    return 0;
}
